import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppState {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING',
  THINKING = 'THINKING',
  SPEAKING = 'SPEAKING',
  ERROR = 'ERROR'
}

export enum Emotion {
  NEUTRAL = 'neutral',
  HAPPY = 'happy',
  SAD = 'sad',
  ANGRY = 'angry',
  CONFUSED = 'confused',
  SURPRISED = 'surprised',
  THINKING = 'thinking'
}

export interface RobotState {
  status: AppState;
  emotion: Emotion;
  transcript: string;
  response: string;
}

import { GoogleGenAI } from "@google/genai";
import { DEFAULT_SYSTEM_PROMPT } from "../constants";

let aiClient: GoogleGenAI | null = null;

// Initialize client lazily or on demand
const getClient = () => {
  if (!aiClient) {
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

export const generateRobotResponse = async (inputText: string): Promise<string> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: inputText,
      config: {
        systemInstruction: DEFAULT_SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });

    return response.text || "[neutral] I am not sure how to respond to that.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "[confused] I seem to be having trouble connecting to my brain.";
  }
};

import React, { useRef, useEffect } from 'react';
import { AppState, Emotion } from '../types';
import { COLOR_MAP } from '../constants';

interface RobotFaceProps {
  state: AppState;
  emotion: Emotion;
  width?: number;
  height?: number;
}

const RobotFace: React.FC<RobotFaceProps> = ({ state, emotion, width = 800, height = 480 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Animation state refs to persist across renders without causing re-renders
  const animState = useRef({
    blinkTimer: 0,
    blinkDuration: 0,
    isBlinking: false,
    pupilX: 0,
    pupilY: 0,
    targetPupilX: 0,
    targetPupilY: 0,
    mouthOpenness: 0,
    breathOffset: 0,
    lastFrameTime: 0,
  });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      // Calculate delta time
      const deltaTime = time - animState.current.lastFrameTime;
      animState.current.lastFrameTime = time;

      // Clear Screen
      ctx.fillStyle = '#111827'; // gray-900
      ctx.fillRect(0, 0, width, height);

      // --- Logic Updates ---

      // Blinking Logic
      if (state === AppState.IDLE || state === AppState.LISTENING || state === AppState.THINKING) {
        if (!animState.current.isBlinking) {
          animState.current.blinkTimer -= deltaTime;
          if (animState.current.blinkTimer <= 0) {
            animState.current.isBlinking = true;
            animState.current.blinkDuration = 150; // ms
          }
        } else {
          animState.current.blinkDuration -= deltaTime;
          if (animState.current.blinkDuration <= 0) {
            animState.current.isBlinking = false;
            // Next blink in 2-5 seconds
            animState.current.blinkTimer = 2000 + Math.random() * 3000;
          }
        }
      } else {
        animState.current.isBlinking = false; // Don't blink while speaking intensely?
      }

      // Pupil Movement Logic (Micro-movements)
      // Jitter targets randomly
      if (Math.random() < 0.05) {
        const range = state === AppState.LISTENING ? 15 : 5;
        animState.current.targetPupilX = (Math.random() - 0.5) * range;
        animState.current.targetPupilY = (Math.random() - 0.5) * range;
      }

      // Smoothly interpolate pupils
      const lerp = 0.1;
      animState.current.pupilX += (animState.current.targetPupilX - animState.current.pupilX) * lerp;
      animState.current.pupilY += (animState.current.targetPupilY - animState.current.pupilY) * lerp;

      // Breathing / Floating effect
      animState.current.breathOffset = Math.sin(time / 500) * 2;

      // Mouth Logic
      let targetMouthOpenness = 0.1; // Default small line
      if (state === AppState.SPEAKING) {
         // Fast sine wave for speaking
         targetMouthOpenness = 0.2 + Math.abs(Math.sin(time / 100)) * 0.5;
      } else if (emotion === Emotion.HAPPY) {
        targetMouthOpenness = 0.3;
      } else if (emotion === Emotion.SURPRISED) {
        targetMouthOpenness = 0.5;
      }

      animState.current.mouthOpenness += (targetMouthOpenness - animState.current.mouthOpenness) * 0.2;


      // --- Drawing ---

      const centerX = width / 2;
      const centerY = height / 2;
      const eyeSpacing = 160;
      const eyeWidth = 100;
      const eyeHeight = 120;

      const baseColor = COLOR_MAP[emotion] || '#06b6d4';

      // Configure Style
      ctx.strokeStyle = baseColor;
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.fillStyle = baseColor;

      // Shadow/Glow
      ctx.shadowColor = baseColor;
      ctx.shadowBlur = 20;

      // Calculate Blink Scale (Y-axis)
      let blinkScale = 1;
      if (animState.current.isBlinking) {
         // Simple parabolic blink
         const progress = 1 - (animState.current.blinkDuration / 150); // 0 to 1
         blinkScale = Math.abs(Math.sin(progress * Math.PI)); 
         // Inverse because sin goes 0->1->0, we want 1->0->1
         blinkScale = 1 - blinkScale; 
      }

      // Extra expression modifiers
      let expressionYOffset = 0;
      let expressionRotate = 0;

      if (emotion === Emotion.SAD) expressionRotate = 0.2;
      if (emotion === Emotion.ANGRY) expressionRotate = -0.2;

      // Helper to draw Eye
      const drawEye = (offsetX: number, isLeft: boolean) => {
        ctx.save();
        ctx.translate(centerX + offsetX, centerY - 50 + animState.current.breathOffset);

        // Apply jitter
        ctx.translate(animState.current.pupilX, animState.current.pupilY);

        // Blink scaling
        ctx.scale(1, blinkScale);

        // Expression rotation
        const rotateDir = isLeft ? 1 : -1;
        ctx.rotate(expressionRotate * rotateDir);

        // Draw Eye Outline
        ctx.beginPath();
        if (emotion === Emotion.ANGRY) {
           // Flat top for angry
           ctx.ellipse(0, 10, eyeWidth / 2, eyeHeight / 2 - 10, 0, 0, Math.PI * 2);
           ctx.fill();
           // Cut top
           ctx.globalCompositeOperation = 'destination-out';
           ctx.beginPath();
           ctx.moveTo(-60, -20);
           ctx.lineTo(60, 0);
           ctx.lineTo(60, -70);
           ctx.lineTo(-60, -70);
           ctx.fill();
           ctx.globalCompositeOperation = 'source-over';
        } else {
           ctx.ellipse(0, 0, eyeWidth / 2, eyeHeight / 2, 0, 0, Math.PI * 2);
           ctx.fill();
        }

        // Inner glare (optional details)
        ctx.fillStyle = '#ffffff';
        ctx.shadowBlur = 0;
        ctx.beginPath();
        ctx.arc(15, -15, 8, 0, Math.PI * 2);
        ctx.fill();

        // Restore for next eye
        ctx.restore();
      };

      // Draw Eyes
      drawEye(-eyeSpacing / 2, true);
      drawEye(eyeSpacing / 2, false);

      // Draw Mouth
      ctx.save();
      ctx.translate(centerX, centerY + 80 + animState.current.breathOffset);
      ctx.fillStyle = baseColor;
      ctx.shadowBlur = 20;

      const mouthWidth = 120;
      const mouthHeight = 20 + (animState.current.mouthOpenness * 60);

      ctx.beginPath();

      if (emotion === Emotion.HAPPY && state !== AppState.SPEAKING) {
         // Smile curve
         ctx.arc(0, -20, 60, 0.2 * Math.PI, 0.8 * Math.PI);
         ctx.stroke();
      } else if (emotion === Emotion.SAD && state !== AppState.SPEAKING) {
         // Frown curve
         ctx.arc(0, 40, 60, 1.2 * Math.PI, 1.8 * Math.PI);
         ctx.stroke();
      } else {
         // Generic speech oval or line
         ctx.ellipse(0, 0, mouthWidth / 2, mouthHeight / 2, 0, 0, Math.PI * 2);
         ctx.fill();
      }

      ctx.restore();

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [state, emotion, width, height]);

  return (
    <canvas 
      ref={canvasRef} 
      width={width} 
      height={height} 
      className="block mx-auto rounded-lg"
    />
  );
};

export default RobotFace;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import RobotFace from './components/RobotFace';
import { generateRobotResponse } from './services/geminiService';
import { AppState, Emotion, RobotState } from './types';
import { Mic, MicOff, Volume2 } from 'lucide-react';

// Declaration for Web Speech API
declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

export default function App() {
  const [robotState, setRobotState] = useState<RobotState>({
    status: AppState.IDLE,
    emotion: Emotion.NEUTRAL,
    transcript: '',
    response: '',
  });

  const [hasPermission, setHasPermission] = useState(false);
  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.continuous = false;
      recognition.lang = 'en-US';
      recognition.interimResults = false;
      recognition.maxAlternatives = 1;

      recognition.onresult = (event: any) => {
        const text = event.results[0][0].transcript;
        console.log('Voice Input:', text);
        handleUserQuery(text);
      };

      recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setRobotState(prev => ({ ...prev, status: AppState.IDLE, emotion: Emotion.CONFUSED }));
      };

      recognition.onend = () => {
        // If we were listening and didn't get a result that triggered a state change, go back to idle
        setRobotState(prev => {
           if (prev.status === AppState.LISTENING) {
             return { ...prev, status: AppState.IDLE };
           }
           return prev;
        });
      };

      recognitionRef.current = recognition;
      setHasPermission(true);
    } else {
      console.warn("Web Speech API not supported in this browser.");
    }
  }, []);

  const speakText = (text: string) => {
    if (!window.speechSynthesis) return;

    // Cancel any current speaking
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    // Try to find a robotic or decent voice
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => v.name.includes('Google US English') || v.name.includes('Samantha'));
    if (preferredVoice) utterance.voice = preferredVoice;

    utterance.pitch = 1.0;
    utterance.rate = 1.0;

    utterance.onstart = () => {
      setRobotState(prev => ({ ...prev, status: AppState.SPEAKING }));
    };

    utterance.onend = () => {
      setRobotState(prev => ({ ...prev, status: AppState.IDLE, emotion: Emotion.NEUTRAL }));
    };

    utterance.onerror = () => {
      setRobotState(prev => ({ ...prev, status: AppState.IDLE }));
    };

    window.speechSynthesis.speak(utterance);
  };

  const handleUserQuery = async (text: string) => {
    setRobotState(prev => ({ ...prev, status: AppState.THINKING, transcript: text, emotion: Emotion.THINKING }));

    const rawResponse = await generateRobotResponse(text);

    // Parse Emotion: look for [emotion] at start
    const emotionRegex = /^\[(\w+)\]/;
    const match = rawResponse.match(emotionRegex);

    let emotion = Emotion.NEUTRAL;
    let spokenText = rawResponse;

    if (match) {
      const tag = match[1].toLowerCase();
      // Remove tag from text
      spokenText = rawResponse.replace(match[0], '').trim();

      // Map tag to Emotion enum
      if (Object.values(Emotion).includes(tag as Emotion)) {
        emotion = tag as Emotion;
      }
    }

    setRobotState(prev => ({
      ...prev,
      response: spokenText,
      emotion: emotion
    }));

    speakText(spokenText);
  };

  const startListening = () => {
    if (recognitionRef.current) {
      try {
        setRobotState(prev => ({ ...prev, status: AppState.LISTENING, emotion: Emotion.NEUTRAL }));
        recognitionRef.current.start();
      } catch (e) {
        // Already started
      }
    } else {
      // Fallback for non-supported browsers or testing
      const text = prompt("Speech API not available. Type your message:");
      if (text) handleUserQuery(text);
    }
  };

  // Pre-load voices
  useEffect(() => {
    window.speechSynthesis.getVoices();
  }, []);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-950 text-white font-mono overflow-hidden relative">

      {/* Robot Face Container - Scales with viewport */}
      <div className="w-full max-w-4xl aspect-[5/3] relative">
        <RobotFace 
          state={robotState.status} 
          emotion={robotState.emotion}
          width={800} // Logical width
          height={480} // Logical height
        />

        {/* Overlay Info */}
        <div className="absolute top-4 left-4 text-xs text-cyan-500/50 uppercase tracking-widest">
           <div>SYS.STATUS: {robotState.status}</div>
           <div>EMO.MODULE: {robotState.emotion.toUpperCase()}</div>
        </div>
      </div>

      {/* Control Bar */}
      <div className="fixed bottom-8 flex flex-col items-center gap-4 w-full px-4">

        {/* Transcript Display */}
        {robotState.transcript && (
          <div className="bg-gray-900/80 border border-gray-800 p-3 rounded-lg max-w-lg w-full text-center text-sm text-cyan-200 fade-in">
            <span className="opacity-50 text-xs uppercase block mb-1">Last Input</span>
            "{robotState.transcript}"
          </div>
        )}

        {/* Interaction Button */}
        <button
          onClick={startListening}
          disabled={robotState.status === AppState.THINKING || robotState.status === AppState.SPEAKING}
          className={`
            group relative flex items-center justify-center gap-3 px-8 py-4 rounded-full 
            transition-all duration-300 transform hover:scale-105 active:scale-95
            ${robotState.status === AppState.LISTENING 
              ? 'bg-red-500 shadow-[0_0_30px_rgba(239,68,68,0.5)]' 
              : 'bg-cyan-600 hover:bg-cyan-500 shadow-[0_0_30px_rgba(8,145,178,0.4)]'
            }
            disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none
          `}
        >
          {robotState.status === AppState.LISTENING ? (
            <>
              <MicOff className="w-6 h-6 animate-pulse" />
              <span className="font-bold tracking-wider">LISTENING...</span>
            </>
          ) : (
            <>
              <Mic className="w-6 h-6" />
              <span className="font-bold tracking-wider">TAP TO SPEAK</span>
            </>
          )}
        </button>

        <div className="text-gray-600 text-xs mt-2">
          Powered by Gemini • Web Speech API
        </div>
      </div>

      {/* Background Grid Decoration */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-10" 
        style={{
          backgroundImage: 'linear-gradient(#0891b2 1px, transparent 1px), linear-gradient(90deg, #0891b2 1px, transparent 1px)',
          backgroundSize: '40px 40px'
        }}
      />
    </div>
  );
}

