import { GoogleGenAI } from "@google/genai";
import { DEFAULT_SYSTEM_PROMPT } from "../constants";

// We use 'any' for Modality here if the type definition isn't fully updated in the environment,
// but based on the SDK it should be an enum. We will access it via the SDK instance or string literal if needed.
// However, per instructions we should import Modality.
import { Modality } from "@google/genai";

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

// --- Text Generation ---

export const generateRobotResponse = async (inputText: string): Promise<string> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: inputText,
      config: {
        systemInstruction: DEFAULT_SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });

    return response.text || "[neutral] I am not sure how to respond to that.";
  } catch (error) {
    console.error("Gemini Text API Error:", error);
    return "[confused] I seem to be having trouble connecting to my brain.";
  }
};

// --- Speech Generation (TTS) ---

export const generateSpeech = async (text: string): Promise<string | null> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' }, // Voices: Puck, Charon, Kore, Fenrir, Zephyr
          },
        },
      },
    });

    // Extract base64 audio data
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    return base64Audio || null;
  } catch (error) {
    console.error("Gemini TTS API Error:", error);
    return null;
  }
};

// --- Audio Decoding Helpers (Raw PCM to AudioBuffer) ---

function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export const createAudioBufferFromPCM = async (
  base64Audio: string, 
  audioContext: AudioContext
): Promise<AudioBuffer> => {
  const uint8Array = base64ToUint8Array(base64Audio);

  // Gemini TTS returns raw PCM 16-bit, 24kHz, Mono
  const sampleRate = 24000;
  const numChannels = 1;

  // Convert Uint8Array bytes to Int16
  const int16Data = new Int16Array(uint8Array.buffer);

  // Create AudioBuffer
  const buffer = audioContext.createBuffer(numChannels, int16Data.length, sampleRate);
  const channelData = buffer.getChannelData(0);

  // Normalize Int16 (-32768 to 32767) to Float32 (-1.0 to 1.0)
  for (let i = 0; i < int16Data.length; i++) {
    channelData[i] = int16Data[i] / 32768.0;
  }

  return buffer;
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import RobotFace from './components/RobotFace';
import { generateRobotResponse, generateSpeech, createAudioBufferFromPCM } from './services/geminiService';
import { AppState, Emotion, RobotState } from './types';
import { Mic, MicOff, Volume2 } from 'lucide-react';

// Declaration for Web Speech API
declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

export default function App() {
  const [robotState, setRobotState] = useState<RobotState>({
    status: AppState.IDLE,
    emotion: Emotion.NEUTRAL,
    transcript: '',
    response: '',
  });

  const [hasPermission, setHasPermission] = useState(false);

  // Refs
  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.continuous = false;
      recognition.lang = 'en-US';
      recognition.interimResults = false;
      recognition.maxAlternatives = 1;

      recognition.onresult = (event: any) => {
        const text = event.results[0][0].transcript;
        console.log('Voice Input:', text);
        handleUserQuery(text);
      };

      recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setRobotState(prev => ({ ...prev, status: AppState.IDLE, emotion: Emotion.CONFUSED }));
      };

      recognition.onend = () => {
        // If we were listening and didn't get a result that triggered a state change, go back to idle
        setRobotState(prev => {
           if (prev.status === AppState.LISTENING) {
             return { ...prev, status: AppState.IDLE };
           }
           return prev;
        });
      };

      recognitionRef.current = recognition;
      setHasPermission(true);
    } else {
      console.warn("Web Speech API not supported in this browser.");
    }

    return () => {
      // Cleanup audio context on unmount
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  // Initialize Audio Context lazily (must be after user gesture)
  const getAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 24000, // Match Gemini TTS
      });
    }
    // Resume if suspended (browser policy)
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
    return audioContextRef.current;
  };

  const playResponseAudio = async (text: string) => {
    try {
      const ctx = getAudioContext();

      // Stop previous audio if playing
      if (currentSourceRef.current) {
        currentSourceRef.current.stop();
      }

      // Fetch TTS Audio
      const base64Audio = await generateSpeech(text);

      if (!base64Audio) {
        throw new Error("No audio generated");
      }

      // Decode Audio
      const audioBuffer = await createAudioBufferFromPCM(base64Audio, ctx);

      // Play Audio
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);

      currentSourceRef.current = source;

      source.onended = () => {
        setRobotState(prev => ({ ...prev, status: AppState.IDLE, emotion: Emotion.NEUTRAL }));
      };

      setRobotState(prev => ({ ...prev, status: AppState.SPEAKING }));
      source.start();

    } catch (error) {
      console.error("Audio Playback Error:", error);
      setRobotState(prev => ({ ...prev, status: AppState.IDLE, emotion: Emotion.SAD }));
    }
  };

  const handleUserQuery = async (text: string) => {
    // 1. Thinking State
    setRobotState(prev => ({ ...prev, status: AppState.THINKING, transcript: text, emotion: Emotion.THINKING }));

    // 2. Generate Text Response & Emotion
    const rawResponse = await generateRobotResponse(text);

    // Parse Emotion: look for [emotion] at start
    const emotionRegex = /^\[(\w+)\]/;
    const match = rawResponse.match(emotionRegex);

    let emotion = Emotion.NEUTRAL;
    let spokenText = rawResponse;

    if (match) {
      const tag = match[1].toLowerCase();
      // Remove tag from text
      spokenText = rawResponse.replace(match[0], '').trim();

      // Map tag to Emotion enum
      if (Object.values(Emotion).includes(tag as Emotion)) {
        emotion = tag as Emotion;
      }
    }

    // Update state with response text and emotion (Robot keeps thinking/preparing speech)
    setRobotState(prev => ({
      ...prev,
      response: spokenText,
      emotion: emotion
    }));

    // 3. Generate and Play Audio (Gemini Voice)
    await playResponseAudio(spokenText);
  };

  const startListening = () => {
    // Initialize audio context on first user interaction to unlock autoplay
    getAudioContext();

    if (recognitionRef.current) {
      try {
        setRobotState(prev => ({ ...prev, status: AppState.LISTENING, emotion: Emotion.NEUTRAL }));
        recognitionRef.current.start();
      } catch (e) {
        // Already started
      }
    } else {
