import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { DEFAULT_SYSTEM_PROMPT } from "../constants";

// --- Audio Processing Helpers ---

function floatTo16BitPCM(float32Array: Float32Array): ArrayBuffer {
  const buffer = new ArrayBuffer(float32Array.length * 2);
  const view = new DataView(buffer);
  let offset = 0;
  for (let i = 0; i < float32Array.length; i++, offset += 2) {
    let s = Math.max(-1, Math.min(1, float32Array[i]));
    view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
  }
  return buffer;
}

function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// --- Live Client ---

export interface LiveClientCallbacks {
  onOpen: () => void;
  onClose: () => void;
  onAudioPlay: () => void;
  onAudioStop: () => void;
  onTranscript?: (text: string, isUser: boolean) => void;
}

export class GeminiLiveClient {
  private ai: GoogleGenAI;
  private inputContext: AudioContext | null = null;
  private outputContext: AudioContext | null = null;
  private inputProcessor: ScriptProcessorNode | null = null;
  private inputSource: MediaStreamAudioSourceNode | null = null;
  private stream: MediaStream | null = null;

  private nextStartTime = 0;
  private scheduledSources: Set<AudioBufferSourceNode> = new Set();

  // Callbacks
  private callbacks: LiveClientCallbacks;

  // State
  private isConnected = false;

  constructor(callbacks: LiveClientCallbacks) {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    this.callbacks = callbacks;
  }

  async connect() {
    if (this.isConnected) return;

    // Initialize Audio Contexts
    this.inputContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    this.outputContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Get Mic Stream
    this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    // Connect to Gemini Live
    const sessionPromise = this.ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
        systemInstruction: DEFAULT_SYSTEM_PROMPT,
      },
      callbacks: {
        onopen: () => {
          this.isConnected = true;
          this.callbacks.onOpen();
          this.startAudioInput(sessionPromise);
        },
        onmessage: (message: LiveServerMessage) => {
          this.handleMessage(message);
        },
        onclose: () => {
          this.disconnect();
        },
        onerror: (err) => {
          console.error("Gemini Live Error:", err);
          this.disconnect();
        }
      }
    });
  }

  private startAudioInput(sessionPromise: Promise<any>) {
    if (!this.inputContext || !this.stream) return;

    this.inputSource = this.inputContext.createMediaStreamSource(this.stream);
    // Use ScriptProcessor for raw PCM access (bufferSize, inputChannels, outputChannels)
    this.inputProcessor = this.inputContext.createScriptProcessor(4096, 1, 1);

    this.inputProcessor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);
      const pcm16 = floatTo16BitPCM(inputData);
      const base64 = arrayBufferToBase64(pcm16);

      sessionPromise.then(session => {
        session.sendRealtimeInput({
          media: {
            mimeType: 'audio/pcm;rate=16000',
            data: base64
          }
        });
      });
    };

    this.inputSource.connect(this.inputProcessor);
    this.inputProcessor.connect(this.inputContext.destination);
  }

  private async handleMessage(message: LiveServerMessage) {
    // 1. Handle Audio
    const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (base64Audio && this.outputContext) {
      await this.queueAudio(base64Audio);
    }

    // 2. Handle Interruption
    if (message.serverContent?.interrupted) {
      this.stopAllAudio();
    }
  }

  private async queueAudio(base64: string) {
    if (!this.outputContext) return;

    // Decode PCM
    const uint8 = base64ToUint8Array(base64);
    const int16 = new Int16Array(uint8.buffer);
    const float32 = new Float32Array(int16.length);
    for (let i = 0; i < int16.length; i++) {
      float32[i] = int16[i] / 32768.0;
    }

    const buffer = this.outputContext.createBuffer(1, float32.length, 24000);
    buffer.copyToChannel(float32, 0);

    // Schedule
    const source = this.outputContext.createBufferSource();
    source.buffer = buffer;
    source.connect(this.outputContext.destination);

    // Sync timing
    const currentTime = this.outputContext.currentTime;
    if (this.nextStartTime < currentTime) {
      this.nextStartTime = currentTime;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += buffer.duration;

    this.scheduledSources.add(source);

    // Notify playing state
    if (this.scheduledSources.size === 1) {
       this.callbacks.onAudioPlay();
    }

    source.onended = () => {
      this.scheduledSources.delete(source);
      if (this.scheduledSources.size === 0) {
        this.callbacks.onAudioStop();
        // Reset time if we ran out of buffer to avoid huge gaps
        if (this.outputContext) {
           this.nextStartTime = this.outputContext.currentTime;
        }
      }
    };
  }

  private stopAllAudio() {
    this.scheduledSources.forEach(s => s.stop());
    this.scheduledSources.clear();
    this.nextStartTime = 0;
    this.callbacks.onAudioStop();
  }

  disconnect() {
    this.isConnected = false;
    this.stopAllAudio();

    // Cleanup Input
    this.inputProcessor?.disconnect();
    this.inputSource?.disconnect();
    this.stream?.getTracks().forEach(t => t.stop());
    this.inputContext?.close();

    // Cleanup Output
    this.outputContext?.close();

    this.callbacks.onClose();
  }
}

import React, { useState, useEffect, useRef } from 'react';
import RobotFace from './components/RobotFace';
import { GeminiLiveClient } from './services/geminiService';
import { AppState, Emotion, RobotState } from './types';
import { Mic, MicOff, Power, Radio } from 'lucide-react';

export default function App() {
  const [robotState, setRobotState] = useState<RobotState>({
    status: AppState.IDLE,
    emotion: Emotion.NEUTRAL,
    transcript: '',
    response: '',
  });

  const [connected, setConnected] = useState(false);
  const clientRef = useRef<GeminiLiveClient | null>(null);

  useEffect(() => {
    // Cleanup on unmount
    return () => {
      if (clientRef.current) {
        clientRef.current.disconnect();
      }
    };
  }, []);

  const toggleConnection = async () => {
    if (connected) {
      clientRef.current?.disconnect();
      setConnected(false);
      setRobotState(prev => ({ ...prev, status: AppState.IDLE }));
    } else {
      // Connect
      setRobotState(prev => ({ ...prev, status: AppState.THINKING, emotion: Emotion.NEUTRAL })); // Transient state while connecting

      const client = new GeminiLiveClient({
        onOpen: () => {
          setConnected(true);
          setRobotState(prev => ({ ...prev, status: AppState.LISTENING, emotion: Emotion.HAPPY }));
        },
        onClose: () => {
          setConnected(false);
          setRobotState(prev => ({ ...prev, status: AppState.IDLE, emotion: Emotion.NEUTRAL }));
        },
        onAudioPlay: () => {
          setRobotState(prev => ({ ...prev, status: AppState.SPEAKING }));
        },
        onAudioStop: () => {
          setRobotState(prev => ({ ...prev, status: AppState.LISTENING }));
        },
      });

      clientRef.current = client;
      try {
        await client.connect();
      } catch (e) {
        console.error("Failed to connect", e);
        setRobotState(prev => ({ ...prev, status: AppState.ERROR, emotion: Emotion.SAD }));
      }
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-950 text-white font-mono overflow-hidden relative">

      {/* Robot Face Container */}
      <div className="w-full max-w-4xl aspect-[5/3] relative">
        <RobotFace 
          state={robotState.status} 
          emotion={robotState.emotion}
          width={800} 
          height={480}
        />

        {/* Status Overlay */}
        <div className="absolute top-4 left-4 flex flex-col gap-1 text-xs tracking-widest pointer-events-none">
           <div className="text-cyan-500/50">SYS.STATUS: {robotState.status}</div>
           <div className="text-cyan-500/50">EMO.MODULE: {robotState.emotion.toUpperCase()}</div>
           <div className={`flex items-center gap-2 ${connected ? 'text-green-500' : 'text-red-500'}`}>
              <div className={`w-2 h-2 rounded-full ${connected ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
              {connected ? 'LIVE_UPLINK_ACTIVE' : 'OFFLINE'}
           </div>
        </div>
      </div>

      {/* Control Bar */}
      <div className="fixed bottom-8 flex flex-col items-center gap-4 w-full px-4">

        {/* Interaction Button */}
        <button
          onClick={toggleConnection}
          className={`
            group relative flex items-center justify-center gap-3 px-8 py-4 rounded-full 
            transition-all duration-300 transform hover:scale-105 active:scale-95 border-2
            ${connected 
              ? 'bg-red-900/20 border-red-500 text-red-500 hover:bg-red-900/40 shadow-[0_0_20px_rgba(239,68,68,0.2)]' 
              : 'bg-cyan-900/20 border-cyan-500 text-cyan-400 hover:bg-cyan-900/40 shadow-[0_0_20px_rgba(34,211,238,0.2)]'
            }
          `}
        >
          {connected ? (
            <>
              <Power className="w-6 h-6" />
              <span className="font-bold tracking-wider">DISCONNECT</span>
            </>
          ) : (
            <>
              <Radio className="w-6 h-6 animate-pulse" />
              <span className="font-bold tracking-wider">CONNECT LIVE</span>
            </>
          )}
        </button>

        <div className="text-gray-600 text-xs mt-2 flex gap-4">
          <span>Gemini Live API</span>
          <span>•</span>
          <span>Low Latency Mode</span>
          <span>•</span>
          <span>Voice: Kore</span>
        </div>
      </div>

      {/* Background Grid Decoration */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-10" 
        style={{
          backgroundImage: 'linear-gradient(#0891b2 1px, transparent 1px), linear-gradient(90deg, #0891b2 1px, transparent 1px)',
          backgroundSize: '40px 40px'
        }}
      />
    </div>
  );
}

import React, { useRef, useEffect } from 'react';
import { AppState, Emotion } from '../types';
import { COLOR_MAP } from '../constants';

interface RobotFaceProps {
  state: AppState;
  emotion: Emotion;
  width?: number;
  height?: number;
}

const RobotFace: React.FC<RobotFaceProps> = ({ state, emotion, width = 800, height = 480 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Animation state refs to persist across renders without causing re-renders
  const animState = useRef({
    blinkTimer: 0,
    blinkDuration: 0,
    isBlinking: false,
    pupilX: 0,
    pupilY: 0,
    targetPupilX: 0,
    targetPupilY: 0,
    mouthOpenness: 0,
    breathOffset: 0,
    lastFrameTime: 0,
  });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      // Calculate delta time
      const deltaTime = time - animState.current.lastFrameTime;
      animState.current.lastFrameTime = time;

      // Clear Screen
      ctx.fillStyle = '#111827'; // gray-900
      ctx.fillRect(0, 0, width, height);

      // --- Logic Updates ---

      // Blinking Logic
      if (state === AppState.IDLE || state === AppState.LISTENING || state === AppState.THINKING) {
        if (!animState.current.isBlinking) {
          animState.current.blinkTimer -= deltaTime;
          if (animState.current.blinkTimer <= 0) {
            animState.current.isBlinking = true;
            animState.current.blinkDuration = 150; // ms
          }
        } else {
          animState.current.blinkDuration -= deltaTime;
          if (animState.current.blinkDuration <= 0) {
            animState.current.isBlinking = false;
            // Next blink in 2-5 seconds
            animState.current.blinkTimer = 2000 + Math.random() * 3000;
          }
        }
      } else {
        animState.current.isBlinking = false;
      }

      // Pupil Movement Logic (Natural Gaze)
      // We want the robot to mostly look at the user (center), but occasionally glance around.

      // 1. Chance to move eyes (Saccades)
      if (Math.random() < 0.01) { // 1% chance per frame (approx every 1.5s at 60fps)
        const range = state === AppState.LISTENING ? 20 : 10;
        animState.current.targetPupilX = (Math.random() - 0.5) * range;
        animState.current.targetPupilY = (Math.random() - 0.5) * range;
      }

      // 2. High chance to return to center (Eye Contact)
      if (Math.random() < 0.005) { // Occasional re-centering
         animState.current.targetPupilX = 0;
         animState.current.targetPupilY = 0;
      }

      // 3. Force center focus when speaking or listening intently
      if (state === AppState.SPEAKING && Math.random() < 0.05) {
         animState.current.targetPupilX = (Math.random() - 0.5) * 5; // Tighter focus
         animState.current.targetPupilY = (Math.random() - 0.5) * 5;
      }


      // Smoothly interpolate pupils
      const lerp = 0.05; // Slower, smoother movement
      animState.current.pupilX += (animState.current.targetPupilX - animState.current.pupilX) * lerp;
      animState.current.pupilY += (animState.current.targetPupilY - animState.current.pupilY) * lerp;

      // Breathing / Floating effect
      animState.current.breathOffset = Math.sin(time / 800) * 3;

      // Mouth Logic
      let targetMouthOpenness = 0.1; // Default small line
      if (state === AppState.SPEAKING) {
         // Fast sine wave for speaking
         targetMouthOpenness = 0.2 + Math.abs(Math.sin(time / 80)) * 0.6;
      } else if (emotion === Emotion.HAPPY) {
        targetMouthOpenness = 0.3;
      } else if (emotion === Emotion.SURPRISED) {
        targetMouthOpenness = 0.5;
      }

      animState.current.mouthOpenness += (targetMouthOpenness - animState.current.mouthOpenness) * 0.2;


      // --- Drawing ---

      const centerX = width / 2;
      const centerY = height / 2;
      const eyeSpacing = 160;
      const eyeWidth = 110;  // Slightly wider
      const eyeHeight = 130; // Slightly taller

      const baseColor = COLOR_MAP[emotion] || '#06b6d4';

      // Configure Style
      ctx.strokeStyle = baseColor;
      ctx.lineWidth = 8;
      ctx.lineCap = 'round';
      ctx.fillStyle = baseColor;

      // Shadow/Glow
      ctx.shadowColor = baseColor;
      ctx.shadowBlur = 25; // Stronger glow

      // Calculate Blink Scale (Y-axis)
      let blinkScale = 1;
      if (animState.current.isBlinking) {
         const progress = 1 - (animState.current.blinkDuration / 150);
         blinkScale = Math.abs(Math.sin(progress * Math.PI)); 
         blinkScale = 1 - blinkScale; 
      }

      // Extra expression modifiers
      let expressionYOffset = 0;
      let expressionRotate = 0;

      if (emotion === Emotion.SAD) expressionRotate = 0.2;
      if (emotion === Emotion.ANGRY) expressionRotate = -0.2;

      // Helper to draw Eye
      const drawEye = (offsetX: number, isLeft: boolean) => {
        ctx.save();
        ctx.translate(centerX + offsetX, centerY - 40 + animState.current.breathOffset);

        // Apply jitter/gaze
        ctx.translate(animState.current.pupilX, animState.current.pupilY);

        // Blink scaling
        ctx.scale(1, blinkScale);

        // Expression rotation
        const rotateDir = isLeft ? 1 : -1;
        ctx.rotate(expressionRotate * rotateDir);

        // Draw Eye Shape
        ctx.beginPath();
        if (emotion === Emotion.ANGRY) {
           // Flat top for angry
           ctx.ellipse(0, 10, eyeWidth / 2, eyeHeight / 2 - 10, 0, 0, Math.PI * 2);
           ctx.fill();
           // Cut top
           ctx.globalCompositeOperation = 'destination-out';
           ctx.beginPath();
           ctx.moveTo(-70, -20);
           ctx.lineTo(70, 0);
           ctx.lineTo(70, -80);
           ctx.lineTo(-70, -80);
           ctx.fill();
           ctx.globalCompositeOperation = 'source-over';
        } else {
           // Standard Oval
           ctx.ellipse(0, 0, eyeWidth / 2, eyeHeight / 2, 0, 0, Math.PI * 2);
           ctx.fill();
        }

        // --- Improved Glare/Reflections ---
        // Moved glare to top-left to avoid "looking right" bias
        ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
        ctx.shadowBlur = 0; // Sharp reflection

        ctx.beginPath();
        // Main Glare (Top Left)
        ctx.ellipse(-20, -25, 12, 8, Math.PI / 4, 0, Math.PI * 2);
        ctx.fill();

        // Secondary Glare (Bottom Right - Subtle)
        ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.beginPath();
        ctx.arc(15, 20, 4, 0, Math.PI * 2);
        ctx.fill();

        // Restore for next eye
        ctx.restore();
      };

      // Draw Eyes
      drawEye(-eyeSpacing / 2, true);
      drawEye(eyeSpacing / 2, false);

      // Draw Mouth
      ctx.save();
      ctx.translate(centerX, centerY + 90 + animState.current.breathOffset);
      ctx.fillStyle = baseColor;
      ctx.shadowBlur = 20;

      const mouthWidth = 100;
      const mouthHeight = 20 + (animState.current.mouthOpenness * 60);

      ctx.beginPath();

      if (emotion === Emotion.HAPPY && state !== AppState.SPEAKING) {
         // Smile curve
         ctx.lineCap = "round";
         ctx.lineWidth = 8;
         ctx.strokeStyle = baseColor;
         ctx.arc(0, -10, 50, 0.2 * Math.PI, 0.8 * Math.PI);
         ctx.stroke();
      } else if (emotion === Emotion.SAD && state !== AppState.SPEAKING) {
         // Frown curve
         ctx.lineWidth = 8;
         ctx.strokeStyle = baseColor;
         ctx.arc(0, 40, 50, 1.2 * Math.PI, 1.8 * Math.PI);
         ctx.stroke();
      } else {
         // Generic speech oval or line
         ctx.ellipse(0, 0, mouthWidth / 2, mouthHeight / 2, 0, 0, Math.PI * 2);
         ctx.fill();
      }

      ctx.restore();

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [state, emotion, width, height]);

  return (
    <canvas 
      ref={canvasRef} 
      width={width} 
      height={height} 
      className="block mx-auto rounded-lg"
    />
  );
};

export default RobotFace;
